async
function
mineBlock(bot , name , count = 1) {
const
blocks = bot.findBlocks ({
matching: (block) => {
return
block.name === name;
},
maxDistance: 32,
count: count ,
});
const
targets = [];
for (let i = 0; i < Math.min(blocks.length , count); i++) {
targets.push(bot.blockAt(blocks[i]));
}
await bot.collectBlock.collect(targets , { ignoreNoPath: true });
}
